import numpy as np

class LabelEncoder:
    def fit(self, labels: np.ndarray) -> 'LabelEncoder':
        self.classes_ = np.array(sorted(set(labels)))
        self.cat_to_idx_ = {c: i for i, c in enumerate(self.classes_)}
        return self

    def transform(self, labels: np.ndarray) -> np.ndarray:
        return np.array([self.cat_to_idx_.get(l, -1) for l in labels], dtype=int)

    def inverse_transform(self, encoded: np.ndarray) -> np.ndarray:
        result = []
        for idx in encoded:
            if 0 <= idx < len(self.classes_):
                result.append(self.classes_[idx])
            else:
                result.append(None)
        return np.array(result)

    def fit_transform(self, labels: np.ndarray) -> np.ndarray:
        return self.fit(labels).transform(labels)
